+fn expr_contains_registered_agg(expr: &Expr, registry: &fsqlite_func::FunctionRegistry) -> bool {
+    match expr {
+        Expr::FunctionCall { name, args, .. } => {
+            if registry
+                .find_aggregate(name, function_args_len(args))
+                .is_some()
+                && !is_scalar_max_min(name, args)
+            {
+                return true;
+            }
+            match args {
+                FunctionArgs::List(exprs) => exprs
+                    .iter()
+                    .any(|expr| expr_contains_registered_agg(expr, registry)),
+                FunctionArgs::Star => false,
+            }
+        }
+        Expr::BinaryOp { left, right, .. } => {
+            expr_contains_registered_agg(left, registry)
+                || expr_contains_registered_agg(right, registry)
+        }
+        Expr::UnaryOp { expr: inner, .. }
+        | Expr::IsNull { expr: inner, .. }
+        | Expr::Cast { expr: inner, .. }
+        | Expr::Collate { expr: inner, .. } => expr_contains_registered_agg(inner, registry),
+        Expr::Between {
+            expr: inner,
+            low,
+            high,
+            ..
+        } => {
+            expr_contains_registered_agg(inner, registry)
+                || expr_contains_registered_agg(low, registry)
+                || expr_contains_registered_agg(high, registry)
+        }
+        Expr::In {
+            expr: inner, set, ..
+        } => {
+            expr_contains_registered_agg(inner, registry)
+                || match set {
+                    InSet::List(exprs) => exprs
+                        .iter()
+                        .any(|expr| expr_contains_registered_agg(expr, registry)),
+                    InSet::Subquery(_) | InSet::Table(_) => false,
+                }
+        }
+        Expr::Like {
+            expr: inner,
+            pattern,
+            escape,
+            ..
+        } => {
+            expr_contains_registered_agg(inner, registry)
+                || expr_contains_registered_agg(pattern, registry)
+                || escape
+                    .as_deref()
+                    .is_some_and(|expr| expr_contains_registered_agg(expr, registry))
+        }
+        Expr::Case {
+            operand,
+            whens,
+            else_expr,
+            ..
+        } => {
+            operand
+                .as_ref()
+                .is_some_and(|expr| expr_contains_registered_agg(expr, registry))
+                || whens.iter().any(|(when_expr, then_expr)| {
+                    expr_contains_registered_agg(when_expr, registry)
+                        || expr_contains_registered_agg(then_expr, registry)
+                })
+                || else_expr
+                    .as_ref()
+                    .is_some_and(|expr| expr_contains_registered_agg(expr, registry))
+        }
+        Expr::JsonAccess {
+            expr: inner, path, ..
+        } => {
+            expr_contains_registered_agg(inner, registry)
+                || expr_contains_registered_agg(path, registry)
+        }
